import { t as prisma } from "../../../../chunks/prisma.js";
//#region src/routes/(app)/certificates/+page.server.ts
var load = async ({ setHeaders }) => {
	setHeaders({ "Cache-Control": "public, max-age=300" });
	return { certificates: await prisma.certificate.findMany({ orderBy: [
		{ featured: "desc" },
		{ order: "asc" },
		{ issueDate: "desc" }
	] }) };
};
//#endregion
export { load };
